#!/usr/bin/env python3
"""
controller_node.py — Smart Traffic Controller
==============================================
Nœud contrôleur : implémente la logique de décision feux de signalisation.

Algorithme de priorité :
  → La direction ayant le plus grand nombre de véhicules en attente
    reçoit le feu VERT.
  → INVARIANT DE SÉCURITÉ : une seule direction verte à la fois.

Contraintes temps réel :
  - Réception données capteur : dès réception (event-driven)
  - Décision + publication    : ≤ 80 ms (WCET)
  - Période maximale          : 200 ms (cycle global)
"""

import rclpy
from rclpy.node import Node
from rclpy.qos import QoSProfile, ReliabilityPolicy, HistoryPolicy
from std_msgs.msg import String

import json
import time
from collections import deque
from typing import Optional

# ──────────────────────────────────────────────
# Constantes
# ──────────────────────────────────────────────
DIRECTIONS        = ["N", "S", "E", "O"]
DECISION_DEADLINE = 80.0          # ms — deadline stricte contrôleur
MIN_GREEN_TIME    = 5.0           # secondes min de vert (anti-flicker)
MAX_GREEN_TIME    = 30.0          # secondes max de vert (équité)
HYSTERESIS        = 3             # seuil min de différence pour changer de priorité
LATENCY_WINDOW    = 200           # taille fenêtre historique latences

RT_QOS = QoSProfile(
    reliability=ReliabilityPolicy.BEST_EFFORT,
    history=HistoryPolicy.KEEP_LAST,
    depth=1,
)

# ──────────────────────────────────────────────
# État d'un feu
# ──────────────────────────────────────────────
LIGHT_GREEN  = "GREEN"
LIGHT_YELLOW = "YELLOW"
LIGHT_RED    = "RED"


class TrafficLightState:
    """Représente l'état courant de tous les feux."""

    def __init__(self):
        self.lights: dict[str, str] = {d: LIGHT_RED for d in DIRECTIONS}
        self.active_green: Optional[str] = None   # direction actuellement verte
        self.green_since:  float          = 0.0   # timestamp début de phase verte

    def set_green(self, direction: str) -> None:
        """
        Passe 'direction' au VERT, toutes les autres au ROUGE.
        INVARIANT : une seule direction verte à la fois.
        """
        assert direction in DIRECTIONS, f"Direction inconnue : {direction}"
        for d in DIRECTIONS:
            self.lights[d] = LIGHT_GREEN if d == direction else LIGHT_RED
        self.active_green = direction
        self.green_since  = time.monotonic()

    def all_red(self) -> None:
        """Phase de transition — tout au rouge."""
        for d in DIRECTIONS:
            self.lights[d] = LIGHT_RED
        self.active_green = None

    def green_duration(self) -> float:
        """Durée en secondes depuis le début de la phase verte courante."""
        if self.active_green is None:
            return 0.0
        return time.monotonic() - self.green_since

    def to_dict(self) -> dict:
        return {
            "lights":       self.lights.copy(),
            "active_green": self.active_green,
            "green_duration_s": round(self.green_duration(), 2),
        }


class PriorityScheduler:
    """
    Ordonnanceur de priorité basé sur le volume de trafic.

    Règles :
      1. La direction avec le maximum de véhicules est candidate.
      2. Hysteresis : on ne change de direction que si la différence
         dépasse HYSTERESIS véhicules (évite les oscillations rapides).
      3. Temps min de vert MIN_GREEN_TIME respecté.
      4. Temps max de vert MAX_GREEN_TIME : changement forcé.
    """

    def __init__(self):
        self._state     = TrafficLightState()
        self._prev_counts: dict[str, int] = {d: 0 for d in DIRECTIONS}

    def decide(self, counts: dict[str, int]) -> tuple[str, TrafficLightState]:
        """
        Prend une décision de feux.

        Returns:
            (raison de la décision, état des feux mis à jour)
        """
        self._prev_counts = counts.copy()
        current_green     = self._state.active_green
        green_duration    = self._state.green_duration()

        # ── Cas 1 : Démarrage (aucun vert actif) ─────────────
        if current_green is None:
            best = self._max_direction(counts)
            self._state.set_green(best)
            return f"INIT → {best} ({counts[best]} véh.)", self._state

        # ── Cas 2 : Durée max atteinte → changement forcé ────
        if green_duration >= MAX_GREEN_TIME:
            best = self._max_direction(counts)
            self._state.set_green(best)
            return (
                f"MAX_TIME ({green_duration:.1f}s) → {best} ({counts[best]} véh.)",
                self._state,
            )

        # ── Cas 3 : Durée min non atteinte → on garde ────────
        if green_duration < MIN_GREEN_TIME:
            return (
                f"MIN_TIME_HOLD ({green_duration:.1f}s < {MIN_GREEN_TIME}s) → {current_green}",
                self._state,
            )

        # ── Cas 4 : Évaluation changement avec hysteresis ────
        best       = self._max_direction(counts)
        count_best = counts[best]
        count_curr = counts[current_green]

        if best != current_green and (count_best - count_curr) >= HYSTERESIS:
            self._state.set_green(best)
            return (
                f"SWITCH {current_green}({count_curr})→{best}({count_best}) Δ={count_best-count_curr}",
                self._state,
            )

        return (
            f"HOLD {current_green} ({count_curr} véh., {green_duration:.1f}s)",
            self._state,
        )

    @staticmethod
    def _max_direction(counts: dict[str, int]) -> str:
        """Retourne la direction avec le maximum de véhicules."""
        return max(counts, key=lambda d: counts[d])


class ControllerNode(Node):
    """
    Nœud ROS2 contrôleur de feux de signalisation.

    Abonnements :
        /traffic_data   (std_msgs/String — JSON)
    Publications :
        /light_commands (std_msgs/String — JSON)
        /controller_stats (std_msgs/String — JSON)
    """

    def __init__(self):
        super().__init__("controller_node")

        # ── Abonnements ───────────────────────────────────────
        self._sub = self.create_subscription(
            String, "/traffic_data", self._on_traffic_data, RT_QOS
        )

        # ── Publications ──────────────────────────────────────
        self._pub_cmd   = self.create_publisher(String, "/light_commands",    RT_QOS)
        self._pub_stats = self.create_publisher(String, "/controller_stats",  RT_QOS)

        # ── Ordonnanceur ──────────────────────────────────────
        self._scheduler = PriorityScheduler()

        # ── Métriques ─────────────────────────────────────────
        self._latencies    = deque(maxlen=LATENCY_WINDOW)
        self._missed        = 0
        self._total_msgs    = 0
        self._last_seq      = -1

        self.get_logger().info(
            f"[ControllerNode] Démarré — deadline={DECISION_DEADLINE} ms | "
            f"min_green={MIN_GREEN_TIME}s | max_green={MAX_GREEN_TIME}s | "
            f"hysteresis={HYSTERESIS} véh."
        )

    # ─────────────────────────────────────────────────────────
    # Callback : données capteur reçues
    # ─────────────────────────────────────────────────────────
    def _on_traffic_data(self, msg: String) -> None:
        t_start = time.monotonic_ns()

        try:
            data = json.loads(msg.data)
        except json.JSONDecodeError as e:
            self.get_logger().error(f"[ControllerNode] JSON invalide : {e}")
            return

        seq    = data.get("seq", -1)
        counts = data.get("counts", {})
        self._total_msgs += 1

        # Vérification perte de messages
        if self._last_seq >= 0 and seq != self._last_seq + 1:
            lost = seq - self._last_seq - 1
            self.get_logger().warn(
                f"[ControllerNode] {lost} message(s) perdu(s) "
                f"(seq attendu={self._last_seq+1}, reçu={seq})"
            )
        self._last_seq = seq

        # ── Décision ─────────────────────────────────────────
        reason, state = self._scheduler.decide(counts)

        # ── Construction commande ─────────────────────────────
        t_decision_ns = time.monotonic_ns()
        decision_ms   = (t_decision_ns - t_start) / 1e6

        command = {
            "seq":            seq,
            "timestamp":      time.time(),
            "decision_ms":    round(decision_ms, 3),
            "reason":         reason,
            "state":          state.to_dict(),
            "counts":         counts,
        }
        out_msg      = String()
        out_msg.data = json.dumps(command)
        self._pub_cmd.publish(out_msg)

        # ── Métriques ─────────────────────────────────────────
        t_end      = time.monotonic_ns()
        latency_ms = (t_end - t_start) / 1e6
        self._latencies.append(latency_ms)

        if latency_ms > DECISION_DEADLINE:
            self._missed += 1
            self.get_logger().error(
                f"[ControllerNode] ⚠ DEADLINE MISS #{self._missed} — "
                f"lat={latency_ms:.2f} ms > {DECISION_DEADLINE} ms (seq={seq})"
            )
        else:
            self.get_logger().debug(
                f"[ControllerNode] seq={seq:05d} | {reason} | lat={latency_ms:.2f} ms"
            )

        # Stats toutes les 10 décisions
        if self._total_msgs % 10 == 0:
            self._publish_stats(latency_ms)

    def _publish_stats(self, last_lat: float) -> None:
        lats = list(self._latencies)
        if not lats:
            return
        lats_sorted = sorted(lats)
        p95 = lats_sorted[int(0.95 * len(lats_sorted))]

        stats = {
            "node":              "controller",
            "timestamp":         time.time(),
            "latency_ms":        last_lat,
            "lat_mean_ms":       sum(lats) / len(lats),
            "lat_max_ms":        max(lats),
            "lat_p95_ms":        p95,
            "missed_deadlines":  self._missed,
            "total_decisions":   self._total_msgs,
            "active_green":      self._scheduler._state.active_green,
        }
        msg      = String()
        msg.data = json.dumps(stats)
        self._pub_stats.publish(msg)

        self.get_logger().info(
            f"[ControllerNode] Stats — "
            f"lat_moy={stats['lat_mean_ms']:.2f} ms | "
            f"p95={p95:.2f} ms | "
            f"missed={self._missed} | "
            f"vert={stats['active_green']}"
        )


# ──────────────────────────────────────────────
# Point d'entrée
# ──────────────────────────────────────────────
def main(args=None):
    rclpy.init(args=args)
    node = ControllerNode()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        node.get_logger().info("[ControllerNode] Arrêt demandé.")
    finally:
        node.destroy_node()
        rclpy.shutdown()


if __name__ == "__main__":
    main()
